CREATE PROCEDURE [dbo].[CARIEXTRE] @P_TARIH1 AS NVARCHAR(15),
@P_TARIH2 AS NVARCHAR(15),
@P_FIRMA INT

AS
SET NOCOUNT ON
TRUNCATE TABLE RowNumber

INSERT RowNumber (CH_REF) 
	SELECT CH_REF FROM CARIHAREKET WITH(NOLOCK)  WHERE TARIH>=@P_TARIH1 AND TARIH<=@P_TARIH2 AND FIRMA_REF=@P_FIRMA 
	ORDER BY TARIH, FIS_NO

select 	TARIH,FIS_NO,
	ISLEM_TURU = CASE
	WHEN FB_REF is not null  THEN 
		(select FIS_ADI FROM FISTURLERI WITH(NOLOCK)  where FIS_TURU=(SELECT FIS_TURU FROM STOKFISLERI WITH(NOLOCK)  WHERE STOKFISLERI.FB_REF=CH.FB_REF))
        WHEN CH_TURU='01' THEN 'Nakit Tahsilat'
	WHEN CH_TURU='02' THEN 'Nakit Ödeme'
	WHEN CH_TURU='03' THEN 'Borç Dekontu'
	WHEN CH_TURU='04' THEN 'Alacak Dekontu'
        END,
	(SELECT FIS_NO FROM STOKFISLERI WITH(NOLOCK)  WHERE STOKFISLERI.FB_REF=CH.FB_REF) FFIS_NO,
	BORC,
	ALACAK,
( ISNULL( (SELECT SUM(BORC)   FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) )DEVREDEN_BORC,
( ISNULL( (SELECT SUM(ALACAK)   FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) )DEVREDEN_ALACAK,
	 ISNULL((  SELECT SUM(BORC)-SUM(ALACAK) FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1),0) DEVREDEN_BAKIYE, 
SUBSTRING(
		RTRIM( 
			CONVERT(CHAR, ABS(ROUND((
  	  ISNULL((( select SUM(BORC)  +   ( ISNULL( (SELECT SUM(BORC)     FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) ) from (SELECT r.RowNumber, e.* FROM RowNumber r WITH(NOLOCK)  JOIN CARIHAREKET e WITH(NOLOCK)  ON r.CH_REF = e.CH_REF ) CHH1  where CHH1.RowNumber <= CH.RowNumber )),0)
	- ISNULL((( select SUM(ALACAK)+   ( ISNULL( (SELECT SUM(ALACAK)   FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) ) from (SELECT r.RowNumber, e.* FROM RowNumber r WITH(NOLOCK)  JOIN CARIHAREKET e WITH(NOLOCK)  ON r.CH_REF = e.CH_REF ) CHH2  where CHH2.RowNumber <= CH.RowNumber )),0)
						 ),2)
					  )
				) 
		      )
,1, LEN(	

		RTRIM( 
			CONVERT(CHAR, ABS(ROUND((
  	  ISNULL((( select SUM(BORC)  +   ( ISNULL( (SELECT SUM(BORC)     FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) ) from (SELECT r.RowNumber, e.* FROM RowNumber r WITH(NOLOCK)  JOIN CARIHAREKET e WITH(NOLOCK)  ON r.CH_REF = e.CH_REF ) CHH1  where CHH1.RowNumber <= CH.RowNumber )),0)
	- ISNULL((( select SUM(ALACAK)+   ( ISNULL( (SELECT SUM(ALACAK)   FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) ) from (SELECT r.RowNumber, e.* FROM RowNumber r WITH(NOLOCK)  JOIN CARIHAREKET e WITH(NOLOCK)  ON r.CH_REF = e.CH_REF ) CHH2  where CHH2.RowNumber <= CH.RowNumber )),0)
						 ),2)
					  )
				) 
		      ) 

	)-2
) 
+ REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(LEFT((

  	  ISNULL((( select SUM(BORC)  +   ( ISNULL( (SELECT SUM(BORC)     FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) ) from (SELECT r.RowNumber, e.* FROM RowNumber r WITH(NOLOCK)  JOIN CARIHAREKET e WITH(NOLOCK)  ON r.CH_REF = e.CH_REF ) CHH1  where CHH1.RowNumber <= CH.RowNumber )),0)
	- ISNULL((( select SUM(ALACAK)+   ( ISNULL( (SELECT SUM(ALACAK)   FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1) ,0) ) from (SELECT r.RowNumber, e.* FROM RowNumber r WITH(NOLOCK)  JOIN CARIHAREKET e WITH(NOLOCK)  ON r.CH_REF = e.CH_REF ) CHH2  where CHH2.RowNumber <= CH.RowNumber )),0)

),1),'-',' (A)'),'0','    '),'1',' (B)'),'2',' (B)'),'3',' (B)'),'4',' (B)'),'5',' (B)'),'6',' (B)'),'7',' (B)'),'8',' (B)'),'9',' (B)')  BAKIYE ,

SUBSTRING(
		RTRIM( 
			CONVERT(CHAR, ABS(ROUND((
		ISNULL((  SELECT SUM(BORC)-SUM(ALACAK) FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1),0)
						 ),2)
					  )
				) 
		      )
,1, LEN(	

		RTRIM( 
			CONVERT(CHAR, ABS(ROUND((
		ISNULL((  SELECT SUM(BORC)-SUM(ALACAK) FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1),0)
						 ),2)
					  )
				) 
		      ) 

	)-2
) 
+ REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(LEFT((

		ISNULL((  SELECT SUM(BORC)-SUM(ALACAK) FROM CARIHAREKET WITH(NOLOCK)   WHERE FIRMA_REF=@P_FIRMA AND TARIH<@P_TARIH1),0)

),1),'-',' (A)'),'0','    '),'1',' (B)'),'2',' (B)'),'3',' (B)'),'4',' (B)'),'5',' (B)'),'6',' (B)'),'7',' (B)'),'8',' (B)'),'9',' (B)')  DEVREDEN_BAKIYE_T ,

	CH_REF,
	MAKBUZ_NO,
	ACIKLAMA,
	FK.*,CONVERT(DATETIME, @P_TARIH1)T1,CONVERT(DATETIME, @P_TARIH2)T2
	,(select sum(BORC) FROM CARIHAREKET WITH(NOLOCK)  WHERE FIRMA_REF=CH.FIRMA_REF  and TARIH>=@P_TARIH1 AND TARIH<=@P_TARIH2) TOPBORC
	,(select sum(ALACAK) FROM CARIHAREKET WITH(NOLOCK)  WHERE FIRMA_REF=CH.FIRMA_REF and TARIH>=@P_TARIH1 AND TARIH<=@P_TARIH2) TOPALACAK
    from (

	SELECT RowNumber, e.* FROM RowNumber r WITH(NOLOCK)  JOIN CARIHAREKET e WITH(NOLOCK)  ON r.CH_REF = e.CH_REF 

) CH, 
	FIRMAKARTI FK WITH(NOLOCK)  WHERE FK.FIRMA_REF=CH.FIRMA_REF 

ORDER BY CH.RowNumber
